module mux_4to1(
    input [3:0] data_in,
    input [1:0] sel,
    output reg y
);

always @(data_in or sel) begin
    case (sel)
        2'b00: y = data_in[0];
        2'b01: y = data_in[1];
        2'b10: y = data_in[2];
        2'b11: y = data_in[3];
        default: y = 1'b0;
    endcase
end

endmodule
